from dataclasses import dataclass, field
from typing import Dict, Any, List, Optional, Callable
from collections import deque
from enum import Enum
import time
import numpy as np

class AlertSeverity(Enum):
    INFO = "info"
    WARNING = "warning"
    CRITICAL = "critical"

@dataclass
class Metric:
    name: str
    value: float
    labels: Dict[str, str] = field(default_factory=dict)
    timestamp: float = field(default_factory=time.time)

@dataclass
class Alert:
    metric_name: str
    message: str
    severity: AlertSeverity
    value: float
    threshold: float
    timestamp: float = field(default_factory=time.time)

@dataclass
class AlertRule:
    metric_name: str
    condition: str
    threshold: float
    severity: AlertSeverity
    message_template: str = "{metric} is {condition} {threshold}"

class LiveMonitoringDashboard:
    def __init__(self, retention_minutes: int = 60):
        self.retention_seconds = retention_minutes * 60
        self.metrics: Dict[str, deque] = {}
        self.alert_rules: List[AlertRule] = []
        self.active_alerts: List[Alert] = []
        self.alert_history: List[Alert] = []

    def record_metric(self, metric: Metric):
        key = metric.name

        if key not in self.metrics:
            self.metrics[key] = deque()

        self.metrics[key].append(metric)
        self._cleanup_old_metrics(key)
        self._check_alerts(metric)

    def add_alert_rule(self, rule: AlertRule):
        self.alert_rules.append(rule)

    def _check_alerts(self, metric: Metric):
        for rule in self.alert_rules:
            if rule.metric_name != metric.name:
                continue

            triggered = False
            if rule.condition == "above" and metric.value > rule.threshold:
                triggered = True
            elif rule.condition == "below" and metric.value < rule.threshold:
                triggered = True

            if triggered:
                message = rule.message_template.format(
                    metric=metric.name,
                    condition=rule.condition,
                    threshold=rule.threshold
                )

                alert = Alert(
                    metric_name=metric.name,
                    message=message,
                    severity=rule.severity,
                    value=metric.value,
                    threshold=rule.threshold
                )

                # Avoid duplicate alerts
                recent_alerts = [
                    a for a in self.active_alerts
                    if a.metric_name == metric.name and
                    time.time() - a.timestamp < 60
                ]

                if not recent_alerts:
                    self.active_alerts.append(alert)

    def _cleanup_old_metrics(self, metric_name: str):
        if metric_name not in self.metrics:
            return

        cutoff = time.time() - self.retention_seconds
        metrics_deque = self.metrics[metric_name]

        while metrics_deque and metrics_deque[0].timestamp < cutoff:
            metrics_deque.popleft()

    def get_metric_summary(
        self,
        metric_name: str,
        window_seconds: int = 300
    ) -> Dict[str, Any]:
        if metric_name not in self.metrics:
            return {"error": "Metric not found"}

        cutoff = time.time() - window_seconds
        values = [
            m.value for m in self.metrics[metric_name]
            if m.timestamp >= cutoff
        ]

        if not values:
            return {
                "count": 0,
                "mean": None,
                "std": None,
                "min": None,
                "max": None
            }

        return {
            "count": len(values),
            "mean": np.mean(values),
            "std": np.std(values),
            "min": np.min(values),
            "max": np.max(values),
            "p50": np.percentile(values, 50),
            "p95": np.percentile(values, 95),
            "latest": values[-1]
        }

    def get_dashboard_state(self) -> Dict[str, Any]:
        metric_summaries = {}
        for metric_name in self.metrics:
            metric_summaries[metric_name] = self.get_metric_summary(metric_name)

        return {
            "metrics": metric_summaries,
            "active_alerts": [
                {
                    "metric": a.metric_name,
                    "message": a.message,
                    "severity": a.severity.value,
                    "value": a.value,
                    "timestamp": a.timestamp
                }
                for a in self.active_alerts
            ],
            "alert_count": len(self.active_alerts),
            "critical_count": sum(
                1 for a in self.active_alerts
                if a.severity == AlertSeverity.CRITICAL
            ),
            "last_updated": time.time()
        }

    def acknowledge_alert(self, alert_index: int):
        if 0 <= alert_index < len(self.active_alerts):
            alert = self.active_alerts.pop(alert_index)
            self.alert_history.append(alert)
